serve(async (req) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: CORS })

  const html = buildHTML()
  return new Response(html, {
    headers: {
      ...CORS,
      'Content-Type': 'text/html; charset=utf-8',
      'Cache-Control': 'no-cache',
    },
  })
})

function buildHTML(): string {
  return `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8"/>
<meta name="viewport" content="width=device-width,initial-scale=1"/>
<title>Network Pulse · Hoppa Destination Intelligence</title>
<style>
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Iowan+Old+Style:ital,wght@0,400;0,700;1,400&display=swap');

:root{
  --pine:#0A5745;--leaf:#14A06B;--ink:#16232C;--ink-soft:#5E6E78;
  --paper:#F5F7F4;--card:#FFF;--line:#E3E9E3;--prior:#517A99;
  --amber:#A66A12;--coral:#C2452D;--salmon:#D98C7A;--leafLight:#E6F4EE;
  --amberLight:#FDF4E3;--coralLight:#FDECEA;
}
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
html,body{height:100%;font-family:'Inter',system-ui,sans-serif;font-size:13px;background:var(--paper);color:var(--ink);-webkit-font-smoothing:antialiased;font-variant-numeric:tabular-nums}
h1,h2,h3{font-family:'Iowan Old Style','Georgia',serif;font-weight:700}

/* ── TIME BAR ── */
#timebar{
  position:sticky;top:0;z-index:100;
  background:var(--pine);padding:10px 20px;
  display:flex;align-items:center;gap:12px;flex-wrap:wrap;
  box-shadow:0 2px 8px rgba(0,0,0,.25);
}
#timebar label{color:rgba(255,255,255,.7);font-size:10px;font-weight:600;text-transform:uppercase;letter-spacing:.07em;white-space:nowrap}
#timebar select{
  background:rgba(255,255,255,.12);border:1px solid rgba(255,255,255,.25);
  color:#fff;border-radius:6px;padding:5px 8px;font-size:12px;font-family:inherit;
  cursor:pointer;outline:none;
}
#timebar select option{background:var(--pine);color:#fff}
.tb-chips{display:flex;gap:6px;margin-left:auto;align-items:center;flex-wrap:wrap}
.chip{
  padding:3px 10px;border-radius:20px;font-size:11px;font-weight:600;
  border:1px solid rgba(255,255,255,.3);color:rgba(255,255,255,.85);
  cursor:default;white-space:nowrap;
}
.chip.valid{border-color:#14A06B;color:#7FFFC4;background:rgba(20,160,107,.15)}
.chip.no-basis{border-color:rgba(255,255,255,.3);color:rgba(255,255,255,.5)}
#date-label{color:rgba(255,255,255,.6);font-size:11px;white-space:nowrap;margin-left:auto;text-align:right;min-width:200px}
.tb-row2{
  background:rgba(0,0,0,.18);padding:5px 20px;
  font-size:11px;color:rgba(255,255,255,.6);text-align:right;
}

/* ── HEADER ── */
.page-header{padding:18px 24px 8px}
.page-header .breadcrumb{font-size:10px;font-weight:600;letter-spacing:.08em;text-transform:uppercase;color:var(--ink-soft);margin-bottom:6px}
.page-header h1{font-size:28px;color:var(--ink)}
.page-header h1 span{color:var(--leaf)}
.page-header .subtitle{font-size:12px;color:var(--ink-soft);margin-top:4px;margin-left:2px}

/* ── NAV TABS ── */
.nav-tabs{display:flex;gap:2px;padding:0 24px;border-bottom:1px solid var(--line);background:var(--card)}
.nav-tab{
  padding:10px 16px;font-size:12px;font-weight:600;color:var(--ink-soft);
  border-bottom:3px solid transparent;cursor:pointer;transition:.15s;white-space:nowrap;
}
.nav-tab:hover{color:var(--ink)}
.nav-tab.active{color:var(--leaf);border-bottom-color:var(--leaf)}

/* ── MAIN CONTENT ── */
.content{padding:20px 24px}
.date-line{
  font-size:12px;font-weight:600;color:var(--ink);margin-bottom:16px;
  display:flex;align-items:center;gap:8px;flex-wrap:wrap;
}
.date-line small{font-size:11px;color:var(--ink-soft);font-weight:400}

/* ── KPI GRID ── */
.kpi-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:12px;margin-bottom:24px}
.kpi{
  background:var(--card);border:1px solid var(--line);border-radius:12px;
  padding:16px 18px;box-shadow:0 1px 3px rgba(0,0,0,.05);position:relative;overflow:hidden;
  display:flex;flex-direction:column;gap:2px;
}
.kpi-src{font-size:9px;font-weight:700;letter-spacing:.08em;text-transform:uppercase;color:var(--ink-soft);margin-bottom:6px}
.kpi-label{font-size:10px;font-weight:600;letter-spacing:.06em;text-transform:uppercase;color:var(--ink-soft)}
.kpi-value{font-size:26px;font-weight:700;color:var(--ink);line-height:1.15;letter-spacing:-.5px;margin:4px 0 6px}
.kpi-was{font-size:11px;color:var(--ink-soft);margin-bottom:4px}
.kpi-was strong{color:var(--ink)}
.kpi-delta{display:inline-flex;align-items:center;gap:4px;padding:3px 9px;border-radius:20px;font-size:11px;font-weight:700;margin-bottom:4px}
.kpi-delta.up{background:var(--leafLight);color:#0A7A52}
.kpi-delta.down{background:var(--coralLight);color:var(--coral)}
.kpi-delta.no-basis{background:#EEF1EE;color:var(--ink-soft)}
.kpi-note{font-size:10px;color:var(--ink-soft);line-height:1.4;margin-top:2px}

/* ── CHART SECTIONS ── */
.section-head{
  display:flex;align-items:baseline;gap:10px;margin-bottom:6px;
  border-left:4px solid var(--leaf);padding-left:10px;
}
.section-head h2{font-size:16px;color:var(--ink)}
.section-head small{font-size:11px;color:var(--ink-soft)}
.chart-card{
  background:var(--card);border:1px solid var(--line);border-radius:12px;
  padding:18px 20px;box-shadow:0 1px 3px rgba(0,0,0,.05);margin-bottom:24px;
}
.chart-note{font-size:10px;color:var(--ink-soft);margin-top:6px}
.chart-legend{display:flex;gap:16px;margin-bottom:10px;flex-wrap:wrap}
.leg-item{display:flex;align-items:center;gap:6px;font-size:11px;color:var(--ink-soft)}
.leg-dot{width:10px;height:10px;border-radius:2px;flex-shrink:0}
.leg-line{width:20px;height:2px;flex-shrink:0}

/* ── METHOD NOTE ── */
.method-box{
  background:var(--card);border:1px solid var(--line);border-radius:10px;
  padding:14px 18px;font-size:11px;color:var(--ink-soft);line-height:1.7;
  margin-top:8px;
}
.method-box strong{color:var(--ink);font-weight:600}

/* ── DETAILS EXPANDER ── */
details summary{cursor:pointer;font-size:10px;color:var(--prior);font-weight:600;margin-top:4px;list-style:none}
details summary::before{content:'▾ ';font-size:10px}
details[open] summary::before{content:'▴ '}
details p{font-size:10px;color:var(--ink-soft);line-height:1.6;margin-top:4px;padding-left:8px}

/* ── VALIDITY BADGES ── */
.validity-bar{
  display:flex;gap:8px;padding:6px 20px;background:rgba(255,255,255,.06);
  border-bottom:1px solid rgba(255,255,255,.1);flex-wrap:wrap;align-items:center;
  font-size:10px;
}
.v-badge{
  padding:2px 8px;border-radius:10px;font-weight:700;font-size:10px;letter-spacing:.03em;
}
.v-badge.valid{background:rgba(20,160,107,.2);color:#7FFFC4;border:1px solid rgba(20,160,107,.4)}
.v-badge.partial{background:rgba(166,106,18,.2);color:#F5C97A;border:1px solid rgba(166,106,18,.4)}
.v-badge.no-basis{background:rgba(255,255,255,.06);color:rgba(255,255,255,.4);border:1px solid rgba(255,255,255,.15)}
.v-label{color:rgba(255,255,255,.55);margin-right:2px}

svg text{font-family:'Inter',sans-serif}
</style>
</head>
<body>

<!-- ── TIME BAR ── -->
<div id="timebar">
  <label>TIMEFRAME</label>
  <select id="tf" onchange="update()">
    <option value="latest_day">Latest day (8 Jul)</option>
    <option value="prior_day">Prior day (7 Jul)</option>
    <option value="past7">Past 7 days</option>
    <option value="past14">Past 14 days</option>
    <option value="past28">Past 28 days</option>
    <option value="past90">Past 90 days</option>
    <option value="this_week">This week to date (W28)</option>
    <option value="last_week" selected>Last full week (W27)</option>
    <option value="this_month">This month to date (Jul)</option>
    <option value="last_month">Last full month (June)</option>
    <option value="this_quarter">This quarter to date (Q3)</option>
    <option value="last_quarter">Last full quarter (Q2)</option>
    <option value="past12m">Past 12 months</option>
    <option value="custom">Custom range…</option>
  </select>
  <label>COMPARE</label>
  <select id="cmp" onchange="update()">
    <option value="prev">Previous period</option>
    <option value="wow">WoW (−7d)</option>
    <option value="mom">MoM (−1 month)</option>
    <option value="qoq">QoQ (−3 months)</option>
    <option value="yoy" selected>YoY (−1 year)</option>
    <option value="none">None</option>
  </select>
  <div id="custom-inputs" style="display:none;gap:6px;align-items:center;display:none">
    <input type="date" id="c-start" value="2025-06-16" min="2024-06-01" max="2026-07-08" onchange="update()" style="background:rgba(255,255,255,.12);border:1px solid rgba(255,255,255,.25);color:#fff;border-radius:6px;padding:4px 8px;font-size:12px;font-family:inherit"/>
    <span style="color:rgba(255,255,255,.5)">→</span>
    <input type="date" id="c-end" value="2026-07-08" min="2024-06-01" max="2026-07-08" onchange="update()" style="background:rgba(255,255,255,.12);border:1px solid rgba(255,255,255,.25);color:#fff;border-radius:6px;padding:4px 8px;font-size:12px;font-family:inherit"/>
  </div>
  <div class="tb-chips">
    <span id="chip-web" class="chip valid">web valid</span>
    <span id="chip-ops" class="chip valid">ops valid</span>
  </div>
  <div id="date-label">—</div>
</div>
<div class="tb-row2" id="tb-label2"></div>

<!-- ── PAGE HEADER ── -->
<div class="page-header">
  <div class="breadcrumb">HOPPA · DESTINATION INTELLIGENCE · NETWORK EDITION</div>
  <h1>All airports <span>to &amp; from</span></h1>
  <div class="subtitle">240 airports · web demand (GA4) + operations (dispatch) · machine-reconciled before delivery</div>
</div>

<!-- ── NAV TABS ── -->
<div class="nav-tabs">
  <div class="nav-tab active">Network pulse</div>
  <div class="nav-tab">Digest</div>
  <div class="nav-tab">Overview</div>
  <div class="nav-tab">Full funnel</div>
  <div class="nav-tab">All airports</div>
  <div class="nav-tab">Audience &amp; channels</div>
  <div class="nav-tab">Operations &amp; revenue</div>
  <div class="nav-tab">Rankings</div>
  <div class="nav-tab">Data &amp; method</div>
</div>

<!-- ── MAIN CONTENT ── -->
<div class="content">
  <div class="date-line" id="date-line-main">—<small id="date-line-sub"></small></div>

  <!-- KPI cards -->
  <div class="kpi-grid" id="kpi-grid"></div>

  <!-- Chart 1: Demand & bookings week by week (fixed) -->
  <div class="section-head"><h2>Demand &amp; bookings, week by week</h2></div>
  <div class="chart-card">
    <div class="chart-legend">
      <div class="leg-item"><div class="leg-dot" style="background:var(--leaf)"></div>Searches (left axis)</div>
      <div class="leg-item"><div class="leg-line" style="background:var(--prior)"></div>Transactions (right axis)</div>
      <div class="leg-item"><div class="leg-dot" style="background:var(--leaf);opacity:.45"></div>Partial week</div>
    </div>
    <div id="chart1-wrap" style="position:relative;overflow:hidden">
      <svg id="chart1" width="100%" style="display:block"></svg>
    </div>
    <div class="chart-note">Bars = searches · line = transactions · hollow = partial week.</div>
  </div>

  <!-- Chart 2: Operations month by month (fixed) -->
  <div class="section-head"><h2>Operations, month by month</h2></div>
  <div class="chart-card">
    <div class="chart-note" style="margin-bottom:8px">All channels, net of cancellations · salmon bars = Feb–Mar 2025, shown at true net value but containing migration backfill — excluded from every comparison (Mar 2025 clips the scale; its value is printed on the bar).</div>
    <div class="chart-legend">
      <div class="leg-item"><div class="leg-dot" style="background:var(--pine)"></div>Net bookings</div>
      <div class="leg-item"><div class="leg-line" style="background:var(--amber)"></div>Net TTV £ (right axis)</div>
      <div class="leg-item"><div class="leg-dot" style="background:var(--salmon)"></div>Migration backfill (shown, never compared)</div>
    </div>
    <div id="chart2-wrap" style="position:relative;overflow:hidden">
      <svg id="chart2" width="100%" style="display:block"></svg>
    </div>
  </div>

  <!-- Method note -->
  <div class="method-box">
    <strong>Method &amp; provenance.</strong> GA4 export analytics_259261360 (events_20250616–20260708): searches/vehicle-select/payment/purchases, revenue = ecommerce.purchase_revenue (property currency GBP), transactions deduped on ecommerce.transaction_id. Dispatch ads.ads_ride_dispatch_v (partner_type='hoppa'; bookings 2024-01-01–2026-07-09): ride-level dedupe (GROUP BY ride_id, ANY_VALUE(hoppa_SellRate) — SellRate repeats per leg), TTV FX-converted per ride via mapping.mapping_cur_exch_rate (mixed GBP/EUR source), net TTV excludes cancelled rides. ISO weeks via EXTRACT(ISOYEAR/ISOWEEK). Feb–Mar 2025 dispatch = migration burst (mass cancelled backfill), flagged and excluded from every comparison. Built and machine-reconciled 12 Jul 2026. <strong>Data to 8 Jul 2026 (web) / 9 Jul 2026 (ops).</strong>
  </div>
</div>

<script>
// ── EMBEDDED DATA ──
${EMBEDDED_DATA}

// ── CONSTANTS ──
const BASE = new Date('2024-06-01T00:00:00Z');
const GA4_START = 382; // 2025-06-16
const GA4_END   = 767; // 2026-07-08
const OPS_END   = 768; // 2026-07-09
// Migration burst offsets (Feb 2025 = 245, Mar 2025 = 273)
const MIG_START = 245; // 2025-02-01
const MIG_END   = 303; // 2025-03-31

function dayOffset(dateStr) {
  const d = new Date(dateStr + 'T00:00:00Z');
  return Math.round((d - BASE) / 86400000);
}
function offsetToDate(o) {
  const d = new Date(BASE.getTime() + o * 86400000);
  return d.toISOString().slice(0, 10);
}
function parseDate(s) { return new Date(s + 'T00:00:00Z'); }

// ISO week
function isoWeek(dateStr) {
  const d = new Date(dateStr + 'T00:00:00Z');
  const jan4 = new Date(Date.UTC(d.getUTCFullYear(), 0, 4));
  const startOfWeek = new Date(jan4.getTime() - (jan4.getUTCDay() || 7 - 1) * 86400000);
  let wn = Math.floor((d - startOfWeek) / (7 * 86400000)) + 1;
  let wy = d.getUTCFullYear();
  if (wn < 1) { wy--; const dec28 = new Date(Date.UTC(wy, 11, 28)); wn = isoWeekNum(dec28); }
  const dec28 = new Date(Date.UTC(wy, 11, 28));
  const maxW  = isoWeekNum(dec28);
  if (wn > maxW) { wy++; wn = 1; }
  return { week: wn, year: wy };
}
function isoWeekNum(d) {
  const jan4 = new Date(Date.UTC(d.getUTCFullYear(), 0, 4));
  const start = new Date(jan4.getTime() - (jan4.getUTCDay() || 7 - 1) * 86400000);
  return Math.floor((d - start) / (7 * 86400000)) + 1;
}

// ── DATE RANGE COMPUTATION ──
function getRange(tf) {
  // All dates in 'YYYY-MM-DD' strings clamped to dataset bounds
  const today = '2026-07-08'; // last web day
  const opsToday = '2026-07-09';
  let s, e;
  switch(tf) {
    case 'latest_day':  s = e = '2026-07-08'; break;
    case 'prior_day':   s = e = '2026-07-07'; break;
    case 'past7':  s = '2026-07-02'; e = today; break;
    case 'past14': s = '2026-06-25'; e = today; break;
    case 'past28': s = '2026-06-11'; e = today; break;
    case 'past90': s = '2026-04-09'; e = today; break;
    case 'this_week':  s = '2026-07-06'; e = today; break; // Mon W28
    case 'last_week':  s = '2026-06-29'; e = '2026-07-05'; break; // W27
    case 'this_month': s = '2026-07-01'; e = today; break;
    case 'last_month': s = '2026-06-01'; e = '2026-06-30'; break;
    case 'this_quarter': s = '2026-07-01'; e = today; break; // Q3 starts Jul
    case 'last_quarter': s = '2026-04-01'; e = '2026-06-30'; break;
    case 'past12m':    s = '2025-07-09'; e = today; break;
    case 'custom':
      s = document.getElementById('c-start').value;
      e = document.getElementById('c-end').value;
      break;
    default: s = '2026-06-29'; e = '2026-07-05';
  }
  return { s, e };
}

function getCmpRange(cmpType, s, e, tf) {
  if (cmpType === 'none') return null;
  const sd = parseDate(s), ed = parseDate(e);
  const durMs = ed - sd;
  const durDays = Math.round(durMs / 86400000) + 1;

  if (cmpType === 'prev') {
    const ce = new Date(sd.getTime() - 86400000);
    const cs = new Date(ce.getTime() - durMs);
    return { s: cs.toISOString().slice(0,10), e: ce.toISOString().slice(0,10), label: 'previous period' };
  }
  if (cmpType === 'wow') {
    const cs = new Date(sd.getTime() - 7*86400000);
    const ce = new Date(ed.getTime() - 7*86400000);
    return { s: cs.toISOString().slice(0,10), e: ce.toISOString().slice(0,10), label: 'WoW (−7d)' };
  }
  if (cmpType === 'mom') {
    const cs = shiftMonth(sd, -1); const ce = shiftMonth(ed, -1);
    return { s: cs.toISOString().slice(0,10), e: ce.toISOString().slice(0,10), label: 'MoM (−1 month)' };
  }
  if (cmpType === 'qoq') {
    const cs = shiftMonth(sd, -3); const ce = shiftMonth(ed, -3);
    return { s: cs.toISOString().slice(0,10), e: ce.toISOString().slice(0,10), label: 'QoQ (−3 months)' };
  }
  if (cmpType === 'yoy') {
    // Day/week presets: shift -364 days (weekday-aligned, same ISO week)
    // Month/quarter/12m presets: shift -12 calendar months
    const calPresets = ['this_month','last_month','this_quarter','last_quarter','past12m'];
    const tf = document.getElementById('tf').value;
    if (calPresets.includes(tf)) {
      const cs = shiftMonth(sd, -12); const ce = shiftMonth(ed, -12);
      return { s: cs.toISOString().slice(0,10), e: ce.toISOString().slice(0,10), label: 'last year (calendar, −12 months)' };
    } else {
      const cs = new Date(sd.getTime() - 364*86400000);
      const ce = new Date(ed.getTime() - 364*86400000);
      return { s: cs.toISOString().slice(0,10), e: ce.toISOString().slice(0,10), label: 'last year (weekday-aligned, −364d = same ISO week)' };
    }
  }
  return null;
}

function shiftMonth(d, months) {
  const r = new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth() + months, d.getUTCDate()));
  // Clamp day if month is shorter
  if (r.getUTCDate() !== d.getUTCDate()) r.setUTCDate(0);
  return r;
}

// ── SUM DAILY DATA ──
function sumSD(s, e) {
  const so = dayOffset(s), eo = dayOffset(e);
  let vs=0,vvs=0,vpf=0,vp=0,vtx=0,vr=0;
  for(let o=so; o<=eo; o++){
    const d = SD[o];
    if(!d) continue;
    vs+=d[0]; vvs+=d[1]; vpf+=d[2]; vp+=d[3]; vtx+=d[4]; vr+=d[5];
  }
  return {s:vs, vs:vvs, pf:vpf, p:vp, tx:vtx, r:vr};
}
function sumSOD(s, e) {
  const so = dayOffset(s), eo = dayOffset(e);
  let vb=0,vc=0,vtn=0;
  for(let o=so; o<=eo; o++){
    const d = SOD[o];
    if(!d) continue;
    vb+=d[0]; vc+=d[1]; vtn+=d[2];
  }
  return {b:vb, c:vc, tn:vtn};
}
function rangeHasGA4(s, e) {
  const so = dayOffset(s), eo = dayOffset(e);
  // GA4 coverage: 382..767
  return so <= GA4_END && eo >= GA4_START;
}
function rangeHasMig(s, e) {
  const so = dayOffset(s), eo = dayOffset(e);
  return so <= MIG_END && eo >= MIG_START;
}

// ── FORMATTERS ──
function fmtK(n) {
  if (n == null || isNaN(n)) return '—';
  const a = Math.abs(n), sg = n<0?'-':'';
  if (a >= 1e6) return sg + (a/1e6).toFixed(1) + 'M';
  if (a >= 1e4) return sg + Math.round(a/1e3) + 'K';
  if (a >= 1e3) return sg + (a/1e3).toFixed(1) + 'K';
  return sg + Math.round(a).toLocaleString('en-GB');
}
function fmtGBP(n) {
  if (n == null || isNaN(n)) return '—';
  const a = Math.abs(n), sg = n<0?'-':'';
  if (a >= 1e6) return sg+'£'+(a/1e6).toFixed(2)+'M';
  if (a >= 1e3) return sg+'£'+Math.round(a/1e3)+'K';
  return sg+'£'+Math.round(a).toLocaleString('en-GB');
}
function fmtPct(n,dp=2) {
  if (n == null || isNaN(n)) return '—';
  return n.toFixed(dp)+'%';
}
function fmtDelta(cur, prev, isPP=false) {
  if (prev == null || prev === 0) return null;
  if (isPP) {
    const d = cur - prev;
    return { val: d, text: (d>=0?'+':'')+d.toFixed(2)+'pp', up: d>=0 };
  }
  const d = (cur - prev) / Math.abs(prev) * 100;
  return { val: d, text: (d>=0?'+':'')+d.toFixed(1)+'%', up: d>=0 };
}
function fmt2Date(s) {
  const mo = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const d = parseDate(s);
  return d.getUTCDate()+' '+mo[d.getUTCMonth()]+' '+d.getUTCFullYear().toString().slice(2);
}
function isoWeekLabel(s) {
  const {week,year} = isoWeek(s);
  return 'W'+week;
}

// ── CHIP HTML ──
function deltaChip(delta, webValid, opsValid, isOps) {
  if ((isOps && !opsValid) || (!isOps && !webValid) || delta === null) {
    return '<span class="kpi-delta no-basis">no basis</span>';
  }
  const cls = delta.up ? 'up' : 'down';
  const arr = delta.up ? '▲' : '▼';
  return '<span class="kpi-delta '+cls+'">'+arr+' '+delta.text+'</span>';
}

// ── MAIN UPDATE ──
function update() {
  const tf = document.getElementById('tf').value;
  const cmpType = document.getElementById('cmp').value;
  const custDiv = document.getElementById('custom-inputs');
  custDiv.style.display = tf === 'custom' ? 'flex' : 'none';

  const { s, e } = getRange(tf);
  const cmpRange = getCmpRange(cmpType, s, e, tf);

  // Validity
  const webValid = rangeHasGA4(s, e);
  const cmpWebValid = cmpRange ? rangeHasGA4(cmpRange.s, cmpRange.e) : false;
  const webDeltaOk = webValid && cmpWebValid;

  const cmpHasMig = cmpRange ? rangeHasMig(cmpRange.s, cmpRange.e) : false;
  const curHasMig = rangeHasMig(s, e);
  const opsDeltaOk = !cmpHasMig && !curHasMig;

  // Chips
  const cw = document.getElementById('chip-web');
  const co = document.getElementById('chip-ops');
  cw.textContent = webValid ? 'web valid' : 'no basis';
  cw.className = 'chip ' + (webValid ? 'valid' : 'no-basis');
  co.textContent = 'ops valid';
  co.className = 'chip valid';

  // Date label
  const tfEl = document.getElementById('tf');
  const cmpEl = document.getElementById('cmp');
  const tfLabel = tfEl.options[tfEl.selectedIndex].text;
  const durDays = Math.round((parseDate(e) - parseDate(s)) / 86400000) + 1;
  const {week:wn, year:wy} = isoWeek(s);

  let dlabel = fmt2Date(s) + ' – ' + fmt2Date(e) + ' (' + durDays + 'd)';
  document.getElementById('date-line-main').innerHTML =
    '<strong>' + fmt2Date(s) + ' – ' + fmt2Date(e) + '</strong> <small>· ' + tfLabel + '</small>';

  let tb2 = '';
  if (cmpRange) {
    tb2 = fmt2Date(s) + ' – ' + fmt2Date(e) + ' (' + durDays + 'd) · ' + cmpRange.label + ': ' + fmt2Date(cmpRange.s) + ' – ' + fmt2Date(cmpRange.e);
  }
  document.getElementById('tb-label2').textContent = tb2;
  document.getElementById('date-label').textContent = dlabel;

  // Sums
  const cur = sumSD(s, e);
  const curOps = sumSOD(s, e);
  let prv = null, prvOps = null;
  if (cmpRange) { prv = sumSD(cmpRange.s, cmpRange.e); prvOps = sumSOD(cmpRange.s, cmpRange.e); }

  // KPI 4: Search→Book = purchase_events/searches
  const s2b_cur = cur.s > 0 ? cur.p / cur.s * 100 : 0;
  const s2b_prv = (prv && prv.s > 0) ? prv.p / prv.s * 100 : null;
  const s2bDelta = (s2b_prv !== null) ? fmtDelta(s2b_cur, s2b_prv, true) : null;

  // KPI 5&6 net
  const netCur = curOps.b - curOps.c;
  const netPrv = prvOps ? (prvOps.b - prvOps.c) : null;
  const tnPrv = prvOps ? prvOps.tn : null;

  // Deltas
  const dSearch = (prv && webDeltaOk) ? fmtDelta(cur.s, prv.s) : null;
  const dTx = (prv && webDeltaOk) ? fmtDelta(cur.tx, prv.tx) : null;
  const dRev = (prv && webDeltaOk) ? fmtDelta(cur.r, prv.r) : null;
  const dNet = (prvOps && opsDeltaOk) ? fmtDelta(netCur, netPrv) : null;
  const dTtv = (prvOps && opsDeltaOk) ? fmtDelta(curOps.tn, tnPrv) : null;

  // Cancellation rate
  const cancRateCur = curOps.b > 0 ? (curOps.c / curOps.b * 100).toFixed(1) : '0.0';
  const cancRatePrv = (prvOps && prvOps.b > 0) ? (prvOps.c / prvOps.b * 100).toFixed(1) : null;
  const cancNote = cancRatePrv
    ? 'cancellation rate ' + cancRateCur + '% vs ' + cancRatePrv + '%'
    : 'cancellations ' + fmtK(curOps.c);

  // AOV
  const aov = cur.tx > 0 ? Math.round(cur.r / cur.tx) : 0;

  const grid = document.getElementById('kpi-grid');
  grid.innerHTML = [
    // 1 Searches
    kpiCard({
      src:'GA4 · site-wide',
      label:'Searches (site-wide)',
      val: fmtK(cur.s),
      was: prv ? fmtK(prv.s) : null,
      delta: deltaChip(dSearch, webDeltaOk, opsDeltaOk, false),
      note: '',
      suppressed: !webValid,
    }),
    // 2 Web bookings
    kpiCard({
      src:'GA4 · transactions',
      label:'Web bookings (transactions)',
      val: webValid ? fmtK(cur.tx) : '—',
      was: (prv && webDeltaOk) ? fmtK(prv.tx) : null,
      delta: deltaChip(dTx, webDeltaOk, opsDeltaOk, false),
      note: 'IDs spanning midnight can add ≤0.3% on multi-day ranges · purchase events: ' + fmtK(cur.p),
      suppressed: !webValid,
    }),
    // 3 Web revenue
    kpiCard({
      src:'GA4 · GBP',
      label:'Web revenue',
      val: webValid ? fmtGBP(cur.r) : '—',
      was: (prv && webDeltaOk) ? fmtGBP(prv.r) : null,
      delta: deltaChip(dRev, webDeltaOk, opsDeltaOk, false),
      note: 'AOV = £' + aov,
      suppressed: !webValid,
    }),
    // 4 Search→Book
    kpiCard({
      src:'GA4 · purchase ÷ searches',
      label:'Search → book',
      val: webValid ? fmtPct(s2b_cur) : '—',
      was: (s2b_prv !== null && webDeltaOk) ? fmtPct(s2b_prv) : null,
      delta: deltaChip(s2bDelta, webDeltaOk, opsDeltaOk, false),
      note: 'purchase events ÷ searches',
      suppressed: !webValid,
    }),
    // 5 Ops net bookings
    kpiCard({
      src:'Dispatch · all channels',
      label:'Ops net bookings',
      val: fmtK(netCur),
      was: netPrv !== null ? fmtK(netPrv) : null,
      delta: deltaChip(dNet, webDeltaOk, opsDeltaOk, true),
      note: cancNote,
      suppressed: false,
    }),
    // 6 Ops net TTV
    kpiCard({
      src:'Dispatch · FX → GBP',
      label:'Ops net TTV',
      val: fmtGBP(curOps.tn),
      was: (tnPrv !== null && opsDeltaOk) ? fmtGBP(tnPrv) : null,
      delta: deltaChip(dTtv, webDeltaOk, opsDeltaOk, true),
      note: cancNote,
      suppressed: false,
    }),
  ].join('');

  // Render charts
  renderChart1();
  renderChart2();
}

function kpiCard({src, label, val, was, delta, note, suppressed}) {
  return '<div class="kpi">' +
    '<div class="kpi-src">' + src + '</div>' +
    '<div class="kpi-label">' + label + '</div>' +
    '<div class="kpi-value">' + val + '</div>' +
    (was ? '<div class="kpi-was">was <strong>' + was + '</strong></div>' : '') +
    delta +
    (note ? '<div class="kpi-note">' + note + '</div>' : '') +
    (suppressed ? '<div class="kpi-note" style="color:var(--coral)">⚠ outside GA4 export window</div>' : '') +
    '</div>';
}

// ── CHART 1: DEMAND & BOOKINGS WEEK BY WEEK ──
function renderChart1() {
  const svg = document.getElementById('chart1');
  const W = svg.parentElement.offsetWidth || 900;
  const H = 280;
  svg.setAttribute('height', H);
  svg.setAttribute('viewBox', '0 0 ' + W + ' ' + H);

  const PAD = { l:56, r:56, t:20, b:36 };
  const plotW = W - PAD.l - PAD.r;
  const plotH = H - PAD.t - PAD.b;

  // Aggregate by ISO week (2025-W25 to 2026-W28)
  const weeks = [];
  const weekMap = {}; // key => {s:0,tx:0,days:0}

  for (let o = GA4_START; o <= GA4_END; o++) {
    const ds = offsetToDate(o);
    const {week,year} = isoWeek(ds);
    const key = year + '-W' + String(week).padStart(2,'0');
    if (!weekMap[key]) { weekMap[key] = {s:0,tx:0,days:0,label:year+'W'+String(week).padStart(2,'0'),year,week}; weeks.push(key); }
    if (SD[o]) { weekMap[key].s += SD[o][0]; weekMap[key].tx += SD[o][4]; }
    weekMap[key].days++;
  }

  // Sort
  const sortedKeys = [...weeks].sort();
  const labels = sortedKeys.map(k => { const w=weekMap[k]; return (w.year%100)+'W'+String(w.week).padStart(2,'0'); });
  const sVals = sortedKeys.map(k => weekMap[k].s);
  const txVals = sortedKeys.map(k => weekMap[k].tx);
  const partials = sortedKeys.map(k => weekMap[k].days < 7);

  const n = sortedKeys.length;
  const maxS = Math.max(...sVals) * 1.15 || 1;
  const maxTx = Math.max(...txVals) * 1.25 || 1;

  // Y-scale labels
  const sStep = niceStep(maxS/4);
  const txStep = niceStep(maxTx/4);

  let out = '';

  // Grid lines
  for (let i=0; i<=4; i++) {
    const y = PAD.t + plotH - (i/4)*plotH;
    out += '<line x1="'+PAD.l+'" y1="'+y+'" x2="'+(W-PAD.r)+'" y2="'+y+'" stroke="#E3E9E3" stroke-width="0.7"/>';
    const sLbl = fmtK(Math.round(sStep*i));
    const txLbl = fmtK(Math.round(txStep*i));
    out += '<text x="'+(PAD.l-6)+'" y="'+(y+3.5)+'" text-anchor="end" font-size="9" fill="#5E6E78">'+sLbl+'</text>';
    out += '<text x="'+(W-PAD.r+6)+'" y="'+(y+3.5)+'" text-anchor="start" font-size="9" fill="'+('#517A99')+'">'+txLbl+'</text>';
  }

  const barW = Math.min(plotW/n * 0.7, 28);
  const groupW = plotW / n;

  // Bars
  for (let i=0; i<n; i++) {
    const cx = PAD.l + i*groupW + groupW/2;
    const bh = (sVals[i]/maxS) * plotH;
    const opacity = partials[i] ? 0.45 : 1;
    const x = cx - barW/2;
    const y = PAD.t + plotH - bh;
    out += '<rect x="'+x+'" y="'+y+'" width="'+barW+'" height="'+bh+'" rx="2" fill="'+('#14A06B')+'" opacity="'+opacity+'">';
    out += '<title>'+labels[i]+': searches='+fmtK(sVals[i])+', tx='+txVals[i]+'</title></rect>';
  }

  // Tx line
  const pts = txVals.map((v,i) => {
    const cx = PAD.l + i*groupW + groupW/2;
    const y = PAD.t + plotH - (v/maxTx)*plotH;
    return {cx,y,v,partial:partials[i]};
  });
  let path = '';
  pts.forEach((p,i) => { path += (i===0?'M':'L') + p.cx.toFixed(1)+','+p.y.toFixed(1)+' '; });
  out += '<path d="'+path+'" fill="none" stroke="#517A99" stroke-width="1.8" stroke-linejoin="round"/>';

  // Points
  pts.forEach((p,i) => {
    if (p.partial) {
      out += '<circle cx="'+p.cx.toFixed(1)+'" cy="'+p.y.toFixed(1)+'" r="4" fill="white" stroke="#517A99" stroke-width="1.5">';
      out += '<title>'+labels[i]+': tx='+p.v+'</title></circle>';
    } else {
      out += '<circle cx="'+p.cx.toFixed(1)+'" cy="'+p.y.toFixed(1)+'" r="3" fill="#517A99">';
      out += '<title>'+labels[i]+': tx='+p.v+'</title></circle>';
    }
  });

  // X labels — every 4th
  for (let i=0; i<n; i+=4) {
    const cx = PAD.l + i*groupW + groupW/2;
    out += '<text x="'+cx.toFixed(1)+'" y="'+(H-PAD.b+14)+'" text-anchor="middle" font-size="9" fill="#5E6E78">'+labels[i]+'</text>';
  }

  // Axis labels
  out += '<text x="'+(PAD.l-38)+'" y="'+(PAD.t+plotH/2)+'" text-anchor="middle" font-size="9" fill="#14A06B" transform="rotate(-90,'+(PAD.l-38)+','+(PAD.t+plotH/2)+')">Searches</text>';
  out += '<text x="'+(W-PAD.r+38)+'" y="'+(PAD.t+plotH/2)+'" text-anchor="middle" font-size="9" fill="#517A99" transform="rotate(90,'+(W-PAD.r+38)+','+(PAD.t+plotH/2)+')">Transactions</text>';

  svg.innerHTML = out;
}

// ── CHART 2: OPERATIONS MONTH BY MONTH ──
function renderChart2() {
  const svg = document.getElementById('chart2');
  const W = svg.parentElement.offsetWidth || 900;
  const H = 300;
  svg.setAttribute('height', H);
  svg.setAttribute('viewBox', '0 0 ' + W + ' ' + H);

  const PAD = { l:60, r:70, t:30, b:36 };
  const plotW = W - PAD.l - PAD.r;
  const plotH = H - PAD.t - PAD.b;

  // Months: Jan 2025 .. Jul 2026
  const months = [];
  for (let y=2025; y<=2026; y++) {
    const mEnd = (y===2025) ? 12 : 7;
    for (let m=1; m<=mEnd; m++) months.push({y,m});
  }
  const n = months.length;

  function monthKey(y,m) { return y*100+m; }
  function isBackfill(y,m) { return y===2025 && (m===2 || m===3); }
  function isCurrent(y,m) { return y===2026 && m===7; }

  const netB = [], netTtv = [], backfill = [], current = [];
  months.forEach(({y,m}) => {
    const s = y+'-'+String(m).padStart(2,'0')+'-01';
    const lastDay = new Date(Date.UTC(y,m,0)).getUTCDate();
    const e = y+'-'+String(m).padStart(2,'0')+'-'+String(lastDay).padStart(2,'0');
    const sums = sumSOD(s, e);
    const net = sums.b - sums.c;
    netB.push(net);
    netTtv.push(sums.tn);
    backfill.push(isBackfill(y,m));
    current.push(isCurrent(y,m));
  });

  // Scale excludes Feb/Mar 2025 (backfill) for bar axis
  const normalNet = netB.filter((_,i) => !backfill[i]);
  const maxNet = Math.max(...normalNet) * 1.15 || 1;
  const maxTtv = Math.max(...netTtv.filter((_,i) => !backfill[i])) * 1.25 || 1;

  const groupW = plotW / n;
  const barW = Math.min(groupW * 0.72, 40);

  let out = '';

  // Grid
  for (let i=0; i<=4; i++) {
    const y = PAD.t + plotH - (i/4)*plotH;
    out += '<line x1="'+PAD.l+'" y1="'+y+'" x2="'+(W-PAD.r)+'" y2="'+y+'" stroke="#E3E9E3" stroke-width="0.7"/>';
    const nLbl = fmtK(Math.round(maxNet/4*i));
    const tLbl = fmtGBP(Math.round(maxTtv/4*i));
    out += '<text x="'+(PAD.l-6)+'" y="'+(y+3.5)+'" text-anchor="end" font-size="9" fill="#5E6E78">'+nLbl+'</text>';
    out += '<text x="'+(W-PAD.r+6)+'" y="'+(y+3.5)+'" text-anchor="start" font-size="9" fill="'+('#A66A12')+'">'+tLbl+'</text>';
  }

  // Bars
  const MAR25_NET = 50914; // clipped bar value to print
  months.forEach(({y,m},i) => {
    const cx = PAD.l + i*groupW + groupW/2;
    const x = cx - barW/2;
    const v = netB[i];
    let bh, fill, opacity=1;
    if (backfill[i]) {
      bh = Math.min((v/maxNet)*plotH, plotH); // clamp at full height for Mar
      fill = '#D98C7A';
      opacity = m===3 ? 1 : 0.85;
    } else {
      bh = Math.min((v/maxNet)*plotH, plotH);
      fill = '#0A5745';
      opacity = current[i] ? 0.45 : 1;
    }
    const ry = PAD.t + plotH - bh;
    out += '<rect x="'+x+'" y="'+ry+'" width="'+barW+'" height="'+bh+'" rx="2" fill="'+fill+'" opacity="'+opacity+'">';
    out += '<title>'+y+'-'+String(m).padStart(2,'0')+': net='+fmtK(v)+', TTV='+fmtGBP(netTtv[i])+'</title></rect>';

    // Backfill label
    if (m===2 && y===2025) {
      out += '<text x="'+cx+'" y="'+(ry-4)+'" text-anchor="middle" font-size="8" fill="#C2452D" font-weight="600">backfill</text>';
    }
    // Mar 2025 clipped — print value above
    if (m===3 && y===2025) {
      // Zigzag break mark
      const bx = x, bx2 = x+barW, by = ry+10;
      out += '<polyline points="'+bx+','+by+' '+(bx+barW*0.25)+','+(by-5)+' '+(bx+barW*0.5)+','+(by+5)+' '+(bx+barW*0.75)+','+(by-5)+' '+bx2+','+by+'" fill="none" stroke="white" stroke-width="1.5"/>';
      out += '<text x="'+cx+'" y="'+(ry-4)+'" text-anchor="middle" font-size="9" fill="#C2452D" font-weight="700">'+MAR25_NET.toLocaleString('en-GB')+'</text>';
    }
    // Current month label
    if (current[i]) {
      out += '<text x="'+cx+'" y="'+(ry-4)+'" text-anchor="middle" font-size="8" fill="#5E6E78">to-date</text>';
    }
  });

  // TTV Line (skip backfill months)
  let pathD = '';
  months.forEach(({y,m},i) => {
    if (backfill[i]) return;
    const cx = PAD.l + i*groupW + groupW/2;
    const yp = PAD.t + plotH - (netTtv[i]/maxTtv)*plotH;
    pathD += (pathD===''?'M':'L') + cx.toFixed(1)+','+yp.toFixed(1)+' ';
    out += '<circle cx="'+cx.toFixed(1)+'" cy="'+yp.toFixed(1)+'" r="3" fill="#A66A12"><title>'+y+'-'+String(m).padStart(2,'0')+': TTV='+fmtGBP(netTtv[i])+'</title></circle>';
  });
  if (pathD) {
    out = '<path d="'+pathD+'" fill="none" stroke="#A66A12" stroke-width="1.8" stroke-linejoin="round"/>' + out;
  }

  // X labels
  months.forEach(({y,m},i) => {
    const cx = PAD.l + i*groupW + groupW/2;
    const mo = ['','Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'][m];
    const lbl = m===1 ? mo+"'"+String(y).slice(2) : mo;
    out += '<text x="'+cx.toFixed(1)+'" y="'+(H-PAD.b+14)+'" text-anchor="middle" font-size="9" fill="#5E6E78">'+lbl+'</text>';
  });

  svg.innerHTML = out;
}

function niceStep(v) {
  const mag = Math.pow(10, Math.floor(Math.log10(v)));
  for (const f of [1,2,2.5,5,10]) { if (v/mag <= f) return mag*f; }
  return mag*10;
}

// ── INIT ──
update();
window.addEventListener('resize', () => { renderChart1(); renderChart2(); });
</script>
</body>
</html>`;
}
